internal static string FromPascalCase(string input)
{
    var matches = PascalCaseWordPartsRegex().Matches(input);
    if (matches.Count == 0)
    {
        return input;
    }

    var result = string.Join(" ", EnumerateTransformedMatches(matches, input));

    if (IsAllUpperWithSpaces(result))
    {
        result = result.ToLowerInvariant();
    }

    return result.Length > 0
        ? Concat(char.ToUpperInvariant(result[0]), result.AsSpan(1))
        : result;
}

private static IEnumerable<string> EnumerateTransformedMatches(MatchCollection matches, string input)
{
    foreach (Match match in matches)
    {
        var value = match.Value;
        bool allUpper = IsAllUpper(value);
        if (allUpper &&
            (value.Length > 1 || (match.Index > 0 && input[match.Index - 1] == ' ') || value == "I"))
        {
            yield return value;
        }
        else
        {
            yield return value.ToLowerInvariant();
        }
    }
}

private static bool IsAllUpper(string value)
{
    for (int i = 0; i < value.Length; i++)
    {
        if (!char.IsUpper(value[i]))
            return false;
    }
    return true;
}

private static bool IsAllUpperWithSpaces(string value)
{
    bool hasSpace = false;
    for (int i = 0; i < value.Length; i++)
    {
        char c = value[i];
        if (c == ' ')
            hasSpace = true;
        else if (!char.IsUpper(c))
            return false;
    }
    return hasSpace;
}

