public static string Dehumanize(this string input)
{
    var words = input.Split(' ', StringSplitOptions.RemoveEmptyEntries);
    if (words.Length == 0)
    {
        return input;
    }

    if (words.Length == 1)
    {
        return words[0].Humanize().Pascalize();
    }

    // Avoid LINQ — use StringBuilder to concatenate pascalized words directly
    var sb = new System.Text.StringBuilder(input.Length);
    foreach (var word in words)
    {
        var humanized = word.Humanize();
        var titleCased = To.TitleCase.Transform(humanized);
        sb.Append(titleCased.Replace(" ", ""));
    }
    return sb.ToString();
}

